/**
 * Type declarations for Monaco's basic-language Monarch modules.
 * These ESM files export a `conf` (language configuration) and a `language`
 * (Monarch tokenizer definition) but ship without declaration files.
 */

declare module 'monaco-editor/esm/vs/basic-languages/go/go.js' {
  import type { languages } from 'monaco-editor';
  export const conf: languages.LanguageConfiguration;
  export const language: languages.IMonarchLanguage;
}

